import{_ as a,o as i,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Engagement Builder Overview","description":"","frontmatter":{"title":"Engagement Builder Overview","slug":"engagement-builder"},"headers":[],"relativePath":"marketer-hub/engagement-builder.md","filePath":"marketer-hub/engagement-builder.md"}'),n={name:"marketer-hub/engagement-builder.md"};function o(s,e,d,l,p,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Re-targeting is key to re-engaging lapsed users, increasing propensity to purchase and increasing sessions per user.</p><p>Engagement Builder is designed to help you conduct precision retargeting and re-engagement campaigns to drive an even higher return on advertising spend. Using our simple yet precise rule system, you can easily arrange users into engagement groups (i.e. audiences) based on their past purchases, advertising exposure, and in-app behavior.</p><p>Engagement groups are shared automatically with advertising partners and agencies, or added directly to campaigns on advertising platforms.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>Branch connects with your ad network through Engagement Builder.</li><li>Engagement groups are created in the Branch Dashboard defined by specific rules (platform, country, app version etc.) and permissions.</li><li>Engagement groups that meet the criteria will be compiled together to be used for re-engagement campaigns</li></ol><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><h3 id="ios-devices" tabindex="-1">iOS Devices <a class="header-anchor" href="#ios-devices" aria-label="Permalink to &quot;iOS Devices&quot;">​</a></h3><p>Given Engagement Builder&#39;s prominent feature of producing a list of device identifiers for retargeting, results of queries will be dependent upon user opt-ins to sharing their device data through <a href="https://developer.apple.com/app-store/user-privacy-and-data-use/" target="_blank" rel="noreferrer">Apple&#39;s AppTrackingTransparency framework</a>.</p><p>For additional information on changes post iOS 14.5, visit our <a href="./ios-14-faqs.html">FAQ Pages</a>.</p><h3 id="data-availability" tabindex="-1">Data Availability <a class="header-anchor" href="#data-availability" aria-label="Permalink to &quot;Data Availability&quot;">​</a></h3><p>Engagement Builder only supports audiences of up to 6 months of data.</p><h3 id="facebook-data" tabindex="-1">Facebook Data <a class="header-anchor" href="#facebook-data" aria-label="Permalink to &quot;Facebook Data&quot;">​</a></h3><p>Facebook ad interactions are not eligible to be leveraged as signals to add users to audience lists, as would otherwise happen when setting up audience lists with the “Clicked Advert” or “Viewed Advert” criteria options.</p><p>This restriction is enforced to align with Meta&#39;s guidance about how to best protect the privacy of Meta users.</p>',15)])])}const h=a(n,[["render",o]]);export{u as __pageData,h as default};
